import{_ as l,o as i,c as e,ag as r}from"./chunks/framework.DXGyWiRo.js";const b=JSON.parse('{"title":"从运维到内容创作者的转型思考","description":"分享我在运维工作之外做内容创作的思考，包括如何平衡主业与副业、如何找到创作灵感、以及对未来的规划。","frontmatter":{"title":"从运维到内容创作者的转型思考","date":"2024-01-01T00:00:00.000Z","tags":["转型","思考","副业","创作"],"description":"分享我在运维工作之外做内容创作的思考，包括如何平衡主业与副业、如何找到创作灵感、以及对未来的规划。"},"headers":[],"relativePath":"posts/devops-to-creator.md","filePath":"posts/devops-to-creator.md"}'),t={name:"posts/devops-to-creator.md"};function o(h,a,n,s,u,d){return i(),e("div",null,[...a[0]||(a[0]=[r('<h1 id="从运维到内容创作者的转型思考" tabindex="-1">从运维到内容创作者的转型思考 <a class="header-anchor" href="#从运维到内容创作者的转型思考" aria-label="Permalink to &quot;从运维到内容创作者的转型思考&quot;">​</a></h1><p>2023年，我开始尝试在业余时间做内容创作。写公众号文章、运营小红书、分享技术心得......这些尝试让我对「工作」和「副业」有了新的思考。</p><h2 id="🤔-为什么想做副业" tabindex="-1">🤔 为什么想做副业？ <a class="header-anchor" href="#🤔-为什么想做副业" aria-label="Permalink to &quot;🤔 为什么想做副业？&quot;">​</a></h2><h3 id="居安思危" tabindex="-1">居安思危 <a class="header-anchor" href="#居安思危" aria-label="Permalink to &quot;居安思危&quot;">​</a></h3><p>运维工作虽然稳定，但：</p><ul><li>技术更新快，需要持续学习</li><li>35岁危机不是空穴来风</li><li>只靠工资，抗风险能力太弱</li></ul><h3 id="价值延伸" tabindex="-1">价值延伸 <a class="header-anchor" href="#价值延伸" aria-label="Permalink to &quot;价值延伸&quot;">​</a></h3><p>工作几年后，我发现自己积累了很多实战经验：</p><ul><li>踩过很多坑，总结出很多技巧</li><li>对效率工具有独特见解</li><li>这些经验只服务了公司和同事</li></ul><p>为什么不把这些经验分享出去，创造更大价值？</p><h2 id="🚶-我的转型路径" tabindex="-1">🚶 我的转型路径 <a class="header-anchor" href="#🚶-我的转型路径" aria-label="Permalink to &quot;🚶 我的转型路径&quot;">​</a></h2><h3 id="第一阶段-尝试期" tabindex="-1">第一阶段：尝试期 <a class="header-anchor" href="#第一阶段-尝试期" aria-label="Permalink to &quot;第一阶段：尝试期&quot;">​</a></h3><ul><li>开始写公众号，记录技术踩坑</li><li>目的：倒逼自己总结和输出</li><li>状态：佛系更新，没有商业目标</li></ul><h3 id="第二阶段-探索期" tabindex="-1">第二阶段：探索期 <a class="header-anchor" href="#第二阶段-探索期" aria-label="Permalink to &quot;第二阶段：探索期&quot;">​</a></h3><ul><li>开通小红书，分享AI工具</li><li>发现内容创作的乐趣</li><li>开始有粉丝互动和正反馈</li></ul><h3 id="第三阶段-专注期" tabindex="-1">第三阶段：专注期 <a class="header-anchor" href="#第三阶段-专注期" aria-label="Permalink to &quot;第三阶段：专注期&quot;">​</a></h3><ul><li>确定方向：AI工具提效</li><li>建立选题库和素材库</li><li>尝试商业化探索</li></ul><h2 id="💭-转型中的困惑" tabindex="-1">💭 转型中的困惑 <a class="header-anchor" href="#💭-转型中的困惑" aria-label="Permalink to &quot;💭 转型中的困惑&quot;">​</a></h2><h3 id="时间从哪里来" tabindex="-1">时间从哪里来？ <a class="header-anchor" href="#时间从哪里来" aria-label="Permalink to &quot;时间从哪里来？&quot;">​</a></h3><p>这可能是被问最多的问题。我的答案是：</p><ol><li><p><strong>减少无效时间</strong></p><ul><li>刷短视频 → 创作短视频</li><li>玩游戏 → 做内容策划</li></ul></li><li><p><strong>提高效率</strong></p><ul><li>用 AI 工具辅助创作</li><li>建立素材库复用</li></ul></li><li><p><strong>碎片时间利用</strong></p><ul><li>通勤：构思选题</li><li>午休：处理回复</li><li>周末：集中创作</li></ul></li></ol><h3 id="主业副业如何平衡" tabindex="-1">主业副业如何平衡？ <a class="header-anchor" href="#主业副业如何平衡" aria-label="Permalink to &quot;主业副业如何平衡？&quot;">​</a></h3><p><strong>我的原则</strong>：</p><ul><li>主业是根本，不能影响</li><li>副业是探索，不能太功利</li><li>状态好就多写，累了就休息</li></ul><h3 id="数据焦虑怎么办" tabindex="-1">数据焦虑怎么办？ <a class="header-anchor" href="#数据焦虑怎么办" aria-label="Permalink to &quot;数据焦虑怎么办？&quot;">​</a></h3><ul><li>刚做自媒体，数据焦虑很正常</li><li>我的方法：关注过程指标，而非结果指标</li><li>比如：本周发布了3篇，这就是成功</li></ul><h2 id="📚-收获与成长" tabindex="-1">📚 收获与成长 <a class="header-anchor" href="#📚-收获与成长" aria-label="Permalink to &quot;📚 收获与成长&quot;">​</a></h2><h3 id="技能提升" tabindex="-1">技能提升 <a class="header-anchor" href="#技能提升" aria-label="Permalink to &quot;技能提升&quot;">​</a></h3><ul><li><strong>写作能力</strong>：从流水账到有框架的表达</li><li><strong>设计能力</strong>：封面图、排版等</li><li><strong>运营思维</strong>：理解平台规则、用户心理</li></ul><h3 id="认知升级" tabindex="-1">认知升级 <a class="header-anchor" href="#认知升级" aria-label="Permalink to &quot;认知升级&quot;">​</a></h3><blockquote><p>你不是没有特长，只是没有发现</p></blockquote><p>通过创作，我发现自己：</p><ul><li>对效率工具特别感兴趣</li><li>擅长把复杂的技术讲简单</li><li>喜欢帮助别人解决问题</li></ul><h3 id="额外收入" tabindex="-1">额外收入 <a class="header-anchor" href="#额外收入" aria-label="Permalink to &quot;额外收入&quot;">​</a></h3><p>虽然不多，但副业确实带来了：</p><ul><li>广告收入</li><li>付费咨询</li><li>知识产品</li></ul><h2 id="🔮-未来规划" tabindex="-1">🔮 未来规划 <a class="header-anchor" href="#🔮-未来规划" aria-label="Permalink to &quot;🔮 未来规划&quot;">​</a></h2><h3 id="短期-2024" tabindex="-1">短期（2024） <a class="header-anchor" href="#短期-2024" aria-label="Permalink to &quot;短期（2024）&quot;">​</a></h3><ul><li>小红书粉丝突破1万</li><li>公众号文章系统化</li><li>推出第一个付费产品</li></ul><h3 id="中期-3年" tabindex="-1">中期（3年） <a class="header-anchor" href="#中期-3年" aria-label="Permalink to &quot;中期（3年）&quot;">​</a></h3><ul><li>成为AI工具领域的KOL</li><li>建立个人品牌</li><li>探索更多变现路径</li></ul><h3 id="长期" tabindex="-1">长期 <a class="header-anchor" href="#长期" aria-label="Permalink to &quot;长期&quot;">​</a></h3><ul><li>职业转型可能性</li><li>内容创业探索</li><li>保持开放心态</li></ul><h2 id="💡-给同样想转型的你" tabindex="-1">💡 给同样想转型的你 <a class="header-anchor" href="#💡-给同样想转型的你" aria-label="Permalink to &quot;💡 给同样想转型的你&quot;">​</a></h2><h3 id="不要等到准备好" tabindex="-1">不要等到准备好 <a class="header-anchor" href="#不要等到准备好" aria-label="Permalink to &quot;不要等到准备好&quot;">​</a></h3><blockquote><p>完成比完美重要</p></blockquote><h3 id="从小步开始" tabindex="-1">从小步开始 <a class="header-anchor" href="#从小步开始" aria-label="Permalink to &quot;从小步开始&quot;">​</a></h3><ul><li>先写一篇文章</li><li>先发一条小红书</li><li>先建一个社群</li></ul><h3 id="保持初心" tabindex="-1">保持初心 <a class="header-anchor" href="#保持初心" aria-label="Permalink to &quot;保持初心&quot;">​</a></h3><p>为什么做比做什么更重要。想清楚你的动机，才能走得更远。</p><h2 id="✨-写在最后" tabindex="-1">✨ 写在最后 <a class="header-anchor" href="#✨-写在最后" aria-label="Permalink to &quot;✨ 写在最后&quot;">​</a></h2><p>转型不是放弃，而是拓展。运维是我的专业，内容创作是我的热爱。左手技术，右手表达，这条路值得探索。</p><hr><p><em>你也有转型或副业的想法吗？欢迎交流～</em></p>',54)])])}const q=l(t,[["render",o]]);export{b as __pageData,q as default};
